// --- Utility Functions ---
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function formatDate(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  const options = { year: 'numeric', month: 'long', day: 'numeric' };
  return d.toLocaleDateString('en-US', options);
}

function formatMastheadDate() {
  const d = new Date();
  const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
  return d.toLocaleDateString('en-US', options);
}

function picsum(seed, w, h) {
  if (typeof seed === 'string' && seed.startsWith('http')) return seed;
  return `https://picsum.photos/seed/${seed}/${w}/${h}`;
}

function timeAgo(dateStr) {
  const now = new Date();
  const d = new Date(dateStr + 'T12:00:00');
  const diffMs = now - d;
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
  if (diffDays === 0) return 'Today';
  if (diffDays === 1) return 'Yesterday';
  if (diffDays < 7) return `${diffDays} days ago`;
  if (diffDays < 30) return `${Math.floor(diffDays / 7)} weeks ago`;
  return formatDate(dateStr);
}

function slugify(text) {
    return text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

function getArticleBySlug(slug) {
    return articles.find(a => slugify(a.title) === slug);
}

// --- State ---
let shuffledArticles = shuffleArray(articles);
let displayedCount = 0;
const ARTICLES_PER_PAGE = 12;
let currentCategory = 'all';
let currentSearch = '';
let filteredArticles = [];

// --- DOM References ---
const featuredSection = document.getElementById('featured-section');
const articlesGrid = document.getElementById('articles-grid');
const editorsPicks = document.getElementById('editors-picks');
const mostRead = document.getElementById('most-read');
const loadMoreBtn = document.getElementById('load-more-btn');
const loadMoreWrap = document.getElementById('load-more-wrap');
const homepageView = document.getElementById('homepage-view');
const articleView = document.getElementById('article-view');
const articleFull = document.getElementById('article-full');
const moreStoriesGrid = document.getElementById('more-stories-grid');
const categoryHeader = document.getElementById('category-header');
const categoryTitle = document.getElementById('category-title');
const searchInput = document.getElementById('search-input');
const searchBtn = document.getElementById('search-btn');
const navLinks = document.querySelectorAll('.nav-link');
const mobileMenuBtn = document.getElementById('mobile-menu-btn');
const navList = document.getElementById('nav-list');
const ticker = document.getElementById('ticker');

// --- Render Functions ---

function renderTicker() {
  const breakingHeadlines = shuffleArray(articles).slice(0, 6).map(a => a.title);
  // Duplicate for seamless loop
  const all = [...breakingHeadlines, ...breakingHeadlines];
  ticker.innerHTML = all.map(h => `<span>${h}</span>`).join('');
}

function renderMasthead() {
  document.getElementById('masthead-date').textContent = formatMastheadDate();
}

function renderFeatured(arts) {
  if (arts.length === 0) {
    featuredSection.innerHTML = '';
    featuredSection.style.display = 'none';
    return;
  }
  featuredSection.style.display = '';

  const main = arts[0];
  const sides = arts.slice(1, 4);

  let sideHTML = sides.map(a => `
    <div class="featured-side-item">
      <img class="side-img" src="${picsum(a.imageId, 600, 380)}" alt="" loading="lazy">
      <div class="side-category">${a.category}</div>
      <h3 class="side-title"><a href="/${slugify(a.title)}" onclick="openArticle(${a.id});return false;">${a.title}</a></h3>
      <div class="side-byline">By ${a.author} &middot; ${timeAgo(a.date)}</div>
    </div>
  `).join('');

  featuredSection.innerHTML = `
    <div class="featured-main">
      <img class="featured-img" src="${picsum(main.imageId, 900, 506)}" alt="" loading="lazy">
      <div class="featured-category">${main.category}</div>
      <h2 class="featured-title"><a href="/${slugify(main.title)}" onclick="openArticle(${main.id});return false;">${main.title}</a></h2>
      <p class="featured-summary">${main.summary}</p>
      <div class="featured-byline">By ${main.author} &middot; ${formatDate(main.date)}</div>
    </div>
    <div class="featured-secondary">${sideHTML}</div>
  `;
}

function renderArticleCard(a) {
  return `
    <div class="article-card">
      <img class="card-img" src="${picsum(a.imageId, 600, 380)}" alt="" loading="lazy">
      <div class="card-category">${a.category}</div>
      <h3 class="card-title"><a href="/${slugify(a.title)}" onclick="openArticle(${a.id});return false;">${a.title}</a></h3>
      <p class="card-summary">${a.summary}</p>
      <div class="card-byline">By ${a.author} &middot; ${timeAgo(a.date)}</div>
    </div>
  `;
}

function renderGrid(arts, startIndex, count) {
  const slice = arts.slice(startIndex, startIndex + count);
  articlesGrid.innerHTML += slice.map(renderArticleCard).join('');
  return slice.length;
}

function renderSidebar() {
  const picks = shuffleArray(articles).slice(0, 5);
  const reads = shuffleArray(articles).slice(0, 5);

  editorsPicks.innerHTML = picks.map(a => `
    <li>
      <div class="sidebar-item-content">
        <div class="sidebar-item-category">${a.category}</div>
        <div class="sidebar-item-title"><a href="/${slugify(a.title)}" onclick="openArticle(${a.id});return false;">${a.title}</a></div>
      </div>
    </li>
  `).join('');

  mostRead.innerHTML = reads.map(a => `
    <li>
      <div class="sidebar-item-content">
        <div class="sidebar-item-category">${a.category}</div>
        <div class="sidebar-item-title"><a href="/${slugify(a.title)}" onclick="openArticle(${a.id});return false;">${a.title}</a></div>
      </div>
    </li>
  `).join('');
}

function renderArticleFull(a) {
  const bodyParagraphs = a.body.split('\n\n').map(p => `<p>${p}</p>`).join('');

  articleFull.innerHTML = `
    <a href="#" class="article-back" onclick="navigateHome(event);">&larr; Back to Home</a>
    <div class="article-category">${a.category}</div>
    <h1 class="article-headline">${a.title}</h1>
    <p class="article-summary-full">${a.summary}</p>
    <div class="article-meta">
      <span class="meta-author">By ${a.author}</span>
      <span class="meta-divider">|</span>
      <span>${formatDate(a.date)}</span>
    </div>
    <img class="article-hero" src="${picsum(a.imageId, 1000, 562)}" alt="">
    <div class="article-body">${bodyParagraphs}</div>
  `;

  // More stories
  const others = shuffleArray(articles.filter(x => x.id !== a.id)).slice(0, 3);
  moreStoriesGrid.innerHTML = others.map(renderArticleCard).join('');
}

// --- Navigation & Filtering ---

function getFilteredArticles() {
  let arts = [...shuffledArticles];
  if (currentCategory !== 'all') {
    arts = arts.filter(a => a.category === currentCategory);
  }
  if (currentSearch.trim()) {
    const q = currentSearch.toLowerCase();
    arts = arts.filter(a =>
      a.title.toLowerCase().includes(q) ||
      a.summary.toLowerCase().includes(q) ||
      a.category.toLowerCase().includes(q)
    );
  }
  return arts;
}

function renderHomepage() {
  homepageView.style.display = '';
  articleView.style.display = 'none';

  filteredArticles = getFilteredArticles();
  articlesGrid.innerHTML = '';
  displayedCount = 0;

  if (currentCategory === 'all' && !currentSearch.trim()) {
    categoryHeader.style.display = 'none';
    renderFeatured(filteredArticles.slice(0, 4));
    const gridArticles = filteredArticles.slice(4);
    filteredArticles = gridArticles;
    displayedCount = 0;
  } else {
    featuredSection.style.display = 'none';
    featuredSection.innerHTML = '';
    if (currentSearch.trim()) {
      categoryHeader.style.display = '';
      categoryTitle.textContent = `Search results for "${currentSearch}"`;
    } else {
      categoryHeader.style.display = '';
      categoryTitle.textContent = currentCategory;
    }
  }

  const added = renderGrid(filteredArticles, 0, ARTICLES_PER_PAGE);
  displayedCount += added;

  if (displayedCount >= filteredArticles.length) {
    loadMoreWrap.style.display = 'none';
  } else {
    loadMoreWrap.style.display = '';
  }

  renderSidebar();
}

function loadMore() {
  const added = renderGrid(filteredArticles, displayedCount, ARTICLES_PER_PAGE);
  displayedCount += added;
  if (displayedCount >= filteredArticles.length) {
    loadMoreWrap.style.display = 'none';
  }
}

function openArticle(id) {
  const a = articles.find(x => x.id === id);
  if (!a) return;
  homepageView.style.display = 'none';
  articleView.style.display = '';
  renderArticleFull(a);
  window.scrollTo({ top: 0, behavior: 'smooth' });
  history.pushState(null, '', '/' + slugify(a.title));
}

function navigateHome(e) {
  if (e) e.preventDefault();
  currentCategory = 'all';
  currentSearch = '';
  searchInput.value = '';
  updateActiveNav('all');
  shuffledArticles = shuffleArray(articles);
  renderHomepage();
  history.pushState(null, '', '/');
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function filterCategory(cat) {
  currentCategory = cat;
  currentSearch = '';
  searchInput.value = '';
  updateActiveNav(cat);
  renderHomepage();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function updateActiveNav(cat) {
  navLinks.forEach(link => {
    link.classList.toggle('active', link.dataset.category === cat);
  });
}

// --- Event Listeners ---

navLinks.forEach(link => {
  link.addEventListener('click', (e) => {
    e.preventDefault();
    const cat = link.dataset.category;
    filterCategory(cat);
    navList.classList.remove('open');
  });
});

loadMoreBtn.addEventListener('click', loadMore);

searchBtn.addEventListener('click', () => {
  currentSearch = searchInput.value;
  currentCategory = 'all';
  updateActiveNav('all');
  renderHomepage();
});

searchInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter') {
    currentSearch = searchInput.value;
    currentCategory = 'all';
    updateActiveNav('all');
    renderHomepage();
  }
});

mobileMenuBtn.addEventListener('click', () => {
  navList.classList.toggle('open');
});

// --- Path Routing ---
function handleRoute() {
  const path = window.location.pathname;
  if (path && path !== '/') {
    const slug = path.replace(/^\//, '');
    const article = getArticleBySlug(slug);
    if (article) {
      openArticle(article.id);
      return;
    }
  }
  homepageView.style.display = '';
  articleView.style.display = 'none';
  renderHomepage();
}

window.addEventListener('popstate', handleRoute);

// --- Init ---
renderMasthead();
renderTicker();
handleRoute();
